"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[2332],{79821:e=>{e.exports=JSON.parse('{"version":{"pluginId":"use-sage","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"defaultSidebar":[{"type":"link","label":"Fire Science","href":"/use-sage/fire","docId":"fire","unlisted":false},{"type":"link","label":"Drought Mitigation and Prediction","href":"/use-sage/ai-drought-mitigation","docId":"ai-drought-mitigation","unlisted":false}]},"docs":{"ai-drought-mitigation":{"id":"ai-drought-mitigation","title":"AI-Driven Drought Mitigation and Prediction Testbed","description":"The Drought Monitoring Testbed is a cutting-edge platform designed to enhance drought forecasting and mitigation capabilities across diverse land uses and systems. It integrates AI-enabled edge computing resources with specialized sensors, including soil moisture sensors, rainfall sensors, vegetation health sensors, and atmospheric and hydrological instruments. These sensors provide critical data on soil moisture levels, precipitation patterns, vegetation stress, and atmospheric conditions, all of which are essential for predicting drought onset and severity. The testbed\'s networking capabilities will support real-time data transmission and analysis, enabling immediate drought reporting and predictive analytics. This allows for rapid detection of drought conditions and optimized resource allocation, ensuring efficient use of water and other critical resources during droughts. By leveraging these technologies, the testbed significantly enhances drought management and agricultural planning, supporting more effective water resource management.","sidebar":"defaultSidebar"},"fire":{"id":"fire","title":"Sage Cyberinfrastructure in Support of AI for Fire Science","description":"Sage is a cutting-edge cyberinfrastructure testbed funded by the NSF Office of Advanced Cyberinfrastructure to support AI research.  Sage provides real-time environmental monitoring and AI-enabled edge computing at a national scale. By bringing advanced AI to the edge, where data is collected, full-resolution analysis, dynamic automation, and immediate actionable responses can be computed. Each Sage node includes a GPU and AI-optimized software stack connected to instruments such as infrared cameras, RGB cameras, LIDAR, and traditional sensors for air quality and wind, as well as LoRaWAN connected sensors for low-bandwidth measurements such as soil moisture.  With over 100 Sage nodes deployed across 17 states, including fire-prone regions in the Western U.S., the platform supports rapid-response science and sustained observation of ecological systems, agriculture, urban environments, and weather-related hazards.","sidebar":"defaultSidebar"}}}}')}}]);